"use strict";(self.webpackChunkblog=self.webpackChunkblog||[]).push([[5676],{3976:(a,t,n)=>{n.r(t),n.d(t,{data:()=>s});const s={key:"v-75d99ce6",path:"/posts/%E8%B4%9D%E5%A1%9E%E5%B0%94%E6%9B%B2%E7%BA%BF.html",title:"贝塞尔曲线",lang:"en-US",frontmatter:{layout:"Post",title:"贝塞尔曲线",date:"2022-4-5",headerImage:"/img/in-post/2021-10-2/02.png",catalog:!0,tags:["可视化","贝塞尔曲线"]},excerpt:"",headers:[{level:2,title:"1.简介",slug:"_1-简介",children:[{level:3,title:"线性贝塞尔曲线",slug:"线性贝塞尔曲线",children:[]},{level:3,title:"二阶贝塞尔曲线",slug:"二阶贝塞尔曲线",children:[]},{level:3,title:"三阶贝塞尔曲线",slug:"三阶贝塞尔曲线",children:[]},{level:3,title:"n阶贝塞尔曲线",slug:"n阶贝塞尔曲线",children:[]}]},{level:2,title:"2.贝塞尔曲线的数学原理",slug:"_2-贝塞尔曲线的数学原理",children:[{level:3,title:"理解",slug:"理解",children:[]},{level:3,title:"使用代码实现贝塞尔曲线方程",slug:"使用代码实现贝塞尔曲线方程",children:[]}]},{level:2,title:"3.控制贝塞尔的曲率",slug:"_3-控制贝塞尔的曲率",children:[{level:3,title:"理解",slug:"理解-1",children:[]},{level:3,title:"使用代码实现权重基本函数",slug:"使用代码实现权重基本函数",children:[]}]},{level:2,title:"4.通过SVG绘制贝塞尔曲线",slug:"_4-通过svg绘制贝塞尔曲线",children:[{level:3,title:"[1]绘制二次贝塞尔曲线",slug:"_1-绘制二次贝塞尔曲线",children:[{level:4,title:"Q",slug:"q",children:[]},{level:4,title:"T",slug:"t",children:[]}]},{level:3,title:"[2]绘制三次贝塞尔曲线",slug:"_2-绘制三次贝塞尔曲线",children:[{level:4,title:"C",slug:"c",children:[]},{level:4,title:"S",slug:"s",children:[]}]}]},{level:2,title:"5.通过Canvas2D绘制贝塞尔曲线",slug:"_5-通过canvas2d绘制贝塞尔曲线",children:[]}],git:{updatedTime:165448575e4},readingTime:{minutes:12,words:2753},filePathRelative:"posts/贝塞尔曲线.md"}},3421:(a,t,n)=>{n.r(t),n.d(t,{default:()=>o});const s=(0,n(6252).uE)('<h2 id="_1-简介" tabindex="-1"><a class="header-anchor" href="#_1-简介" aria-hidden="true">#</a> 1.简介</h2><p>在计算机看来，所有线条都是“函数”，不管它们是直线还是曲线。而贝塞尔曲线是一种在计算机上表现良好的曲线方程，基本上任何画曲线的地方都会用到它。</p><p><strong>常见应用场景</strong>：计算机辅助设计和计算机辅助制造应用（CAD/CAM），Adobe Illustrator, Photoshop, Inkscape, Gimp等等。还可以应用在一些图形技术中，像矢量图形（SVG），所以说在可视化学习的重要基础知识。</p><p>贝塞尔曲线是线性插值的结果</p><blockquote><p>线性插值（简单理解）：“选出两点之间的一个点”</p></blockquote><p><code>n</code>阶贝塞尔曲线（<code>n+1</code>个控制点)</p><h3 id="线性贝塞尔曲线" tabindex="-1"><a class="header-anchor" href="#线性贝塞尔曲线" aria-hidden="true">#</a> 线性贝塞尔曲线</h3><p>例如：下边这个图中，在<code>P1</code>和<code>P2</code>中插入一个一个点<code>P</code>，定义一个<code>t(0&lt;t&lt;1)</code>来定义P点的位置，得到下面的线性插值函数：(可以根据t来求得出线段上那个点的坐标) $$ P(t)=P_0+(P_1-P_0)=(1-t)P_0+tP_1,t\\in[0,1]\\ t=P_0P1/P_0P_1 $$ <img src="https://img-blog.csdnimg.cn/img_convert/e1bde10310534c4ea55d4ce1a2b594d6.png" alt="image-20220412183748678"></p><h3 id="二阶贝塞尔曲线" tabindex="-1"><a class="header-anchor" href="#二阶贝塞尔曲线" aria-hidden="true">#</a> 二阶贝塞尔曲线</h3><p>上面为一个插值一个点的情况，也成为线性贝塞尔曲线。下面我们在插两值，叫<strong>二次方贝塞尔曲线</strong>。 $$ 在P_0P_1上利用上面的线性公式求出点P&#39;_0，然后在P_1P_2上利用线性公式求出点P_1&#39;,\\最后在P_1&#39;P_2&#39;上利用线性公式 求得最终贝塞尔曲线上的点P&#39;&#39;_0\\ P&#39;_0=(1-t)P_0+tP_1\\ P&#39;_1=(1-t)P_1+tP_2\\ P(t)=(1-t)P&#39;_0+tP&#39;_1=(1-t)^2 P_0+2t(1-t)P_1+t^2P_2, t\\in[0,1]\\ $$ <img src="https://img-blog.csdnimg.cn/5f103462ab4c4ed3a1743e06e4ba2a57.png" alt="在这里插入图片描述"></p><blockquote><p>把两个插值建立P建立连接，在连接线中在以同样的参数t建立一个插值，这样线性的曲线就叫二次方贝塞尔曲线</p></blockquote><h3 id="三阶贝塞尔曲线" tabindex="-1"><a class="header-anchor" href="#三阶贝塞尔曲线" aria-hidden="true">#</a> 三阶贝塞尔曲线</h3><p>下面还有三次线性插值[<strong>最常用的</strong>]（在在插值P的连线上递归的创建同t的线性插值）</p><p>三阶的公式推导同理二阶的，最终为 $$ P(t)=(1-t)^3P_0+3t(1-t)^2P_1+3t^2(1-t)P_2+t^3P_3,t\\in[0,1] $$ <img src="https://img-blog.csdnimg.cn/img_convert/2c7608795120b3d9f513c42f98e7ea18.gif" alt="three"></p><p>还可以将点移动到任意位置（贝塞尔曲线便跟着发生改变了）</p><p><img src="https://img-blog.csdnimg.cn/2fe567b01be04c3aa93a05c81d8b2f95.png" alt="在这里插入图片描述"></p><p>其中的每个新点都是从前面的几个点形成的，直到形成贝塞尔曲线，递归到最后一个点（称为<code>De Casteljau</code>算法）。</p><p><img src="https://img-blog.csdnimg.cn/img_convert/dfb7b95d3c444474604f90f76c043b45.png" alt="image-20220414113042526"> $$ A=(1-t)P_0+tP_1\\ B=(1-t)P_1+tP_2\\ C=(1-t)P_2+tP_3\\ D=(1-t)A+tB\\ E=(1-t)V+tC\\ P=(1-t)D+tE\\ $$</p><h3 id="n阶贝塞尔曲线" tabindex="-1"><a class="header-anchor" href="#n阶贝塞尔曲线" aria-hidden="true">#</a> n阶贝塞尔曲线</h3><p>$$ 给定点P_0,P_1,P_2...P_n $$ <img src="https://img-blog.csdnimg.cn/img_convert/50a83ea6cb255a7f75be37f76776e2f2.png" alt="image-20220414114107581"></p><h2 id="_2-贝塞尔曲线的数学原理" tabindex="-1"><a class="header-anchor" href="#_2-贝塞尔曲线的数学原理" aria-hidden="true">#</a> 2.贝塞尔曲线的数学原理</h2><h3 id="理解" tabindex="-1"><a class="header-anchor" href="#理解" aria-hidden="true">#</a> 理解</h3><p>贝塞尔曲线是“参数”方程的一种形式。</p><blockquote><p>补充普通参数方程的一些特性：参数曲线不像一般函数那样一个方程一个变量，它是多个方程，但只有一个变量。如果我们改变了<em>t</em>的值，*fa(t)<em>和</em>fb(t)*的输出都会发生变化。</p><p>例如圆的参数方程</p><p><img src="https://img-blog.csdnimg.cn/img_convert/68e60cb4e658aae3a451050f463617ca.png" alt="img"></p></blockquote><p>与普通参数方式不同的是贝塞尔曲线的t使用了多项式，贝塞尔曲线不是x的多项式，它是<em>t</em>的多项式，<em>t</em>的值被限制在0和1之间（t项次便代表有多少个点构成的贝塞尔曲线）</p><p><img src="https://img-blog.csdnimg.cn/img_convert/df577520b6c7f753dc9c77d3abdd791d.png" alt="img"></p><p>把t去掉后</p><p><img src="https://img-blog.csdnimg.cn/img_convert/671711f423853848f307fea95f8e7d0d.png" alt="img"></p><blockquote><p>可以发现，每次我们增加一个维度，只要简单地将头尾置为1，中间的操作都是“将上面的两个数字相加”</p><p>这便是这些参数的原理了</p></blockquote><p>还有一个简单的办法可以弄清参数项怎么工作的：如果我们将*(1-t)<em>重命名为</em>a*，将<em>t</em>重命名为<em>b</em>，暂时把权重删掉，可以得到这个：</p><p><img src="https://img-blog.csdnimg.cn/img_convert/ab9e98613e816c18e0f7209aafd6cb05.png" alt="img"></p><p>基本上它就是“每个<em>a</em>和<em>b</em>结合项”的和，在每个加号后面逐步的将<em>a</em>换成<em>b</em>。最终可以得出一般方程：</p><p><img src="https://img-blog.csdnimg.cn/img_convert/b26e99cecc07ddcecdab1edda7cf78a2.png" alt="img"></p><blockquote><p>这些都是和上边得图形示例对应得上的，可以到回去比对分析</p></blockquote><h3 id="使用代码实现贝塞尔曲线方程" tabindex="-1"><a class="header-anchor" href="#使用代码实现贝塞尔曲线方程" aria-hidden="true">#</a> 使用代码实现贝塞尔曲线方程</h3><div class="language-javascript ext-js"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">Bezier</span><span class="token punctuation">(</span><span class="token parameter"><span class="token number">2</span><span class="token punctuation">,</span>t</span><span class="token punctuation">)</span><span class="token operator">:</span>\n  t2 <span class="token operator">=</span> t <span class="token operator">*</span> t\n  mt <span class="token operator">=</span> <span class="token number">1</span><span class="token operator">-</span>t\n  mt2 <span class="token operator">=</span> mt <span class="token operator">*</span> mt\n  <span class="token keyword">return</span> mt2 <span class="token operator">+</span> <span class="token number">2</span><span class="token operator">*</span>mt<span class="token operator">*</span>t <span class="token operator">+</span> t2\n\n<span class="token keyword">function</span> <span class="token function">Bezier</span><span class="token punctuation">(</span><span class="token parameter"><span class="token number">3</span><span class="token punctuation">,</span>t</span><span class="token punctuation">)</span><span class="token operator">:</span>\n  t2 <span class="token operator">=</span> t <span class="token operator">*</span> t\n  t3 <span class="token operator">=</span> t2 <span class="token operator">*</span> t\n  mt <span class="token operator">=</span> <span class="token number">1</span><span class="token operator">-</span>t\n  mt2 <span class="token operator">=</span> mt <span class="token operator">*</span> mt\n  mt3 <span class="token operator">=</span> mt2 <span class="token operator">*</span> mt\n  <span class="token keyword">return</span> mt3 <span class="token operator">+</span> <span class="token number">3</span><span class="token operator">*</span>mt2<span class="token operator">*</span>t <span class="token operator">+</span> <span class="token number">3</span><span class="token operator">*</span>mt<span class="token operator">*</span>t2 <span class="token operator">+</span> t3\n</code></pre></div><h2 id="_3-控制贝塞尔的曲率" tabindex="-1"><a class="header-anchor" href="#_3-控制贝塞尔的曲率" aria-hidden="true">#</a> 3.控制贝塞尔的曲率</h2><h3 id="理解-1" tabindex="-1"><a class="header-anchor" href="#理解-1" aria-hidden="true">#</a> 理解</h3><p>贝塞尔曲线是插值方程（就像所有曲线一样），这表示它们取一系列的点，生成一些处于这些点之间的值。</p><p>这里对于贝塞尔曲线又多了一个重要的概念：<strong>权重/对总曲线的贡献</strong>，通过控制权重来改变相应的曲率</p><p>实际上，我们可以将每个点对方程产生的曲线做出的贡献进行可视化，因此可以看出曲线上哪些点是重要的，它们处于什么位置。</p><p><img src="https://img-blog.csdnimg.cn/img_convert/49b6e162f3bde5a9567e32889d045daf.png" alt="image-20220412203509274"></p><blockquote><p>上面每条线对应着相应的个点，根据<code>t</code>的变化可以计算出某个点对贝塞尔曲线的贡献/权重<code>S</code></p><p>通过可视化可以大概看出在所有控制点中起点和终点对曲线形状的贡献比其他点更大些</p></blockquote><p>如果我们要改变曲线（改变曲率），就需要改变每个点的权重，来实现有效地改变插值。</p><p>可以很直接地做到这个：只要用一个值乘以每个点，来改变它的强度。这个值照惯例称为“权重”，可以将它加入原始的贝塞尔函数：</p><p><img src="https://img-blog.csdnimg.cn/img_convert/133bf86bfeab44be0e4f0a58414b8f7b.png" alt="img"></p><p>“权重”是我们想让曲线所拥有的坐标值：对于一条<code>n</code>阶曲线，<code>w0</code>是起始坐标，<code>wn</code>是终点坐标，中间的所有点都是控制点坐标。假设说一条曲线的起点为<code>（110，150）</code>，终点为<code>（210，30）</code>，并受点<code>（25，190）</code>和点<code>（210，250）</code>的控制，贝塞尔曲线方程就为：</p><p><img src="https://img-blog.csdnimg.cn/img_convert/a062a265d61eb3c9033ac5ecb02c6929.png" alt="img"></p><h3 id="使用代码实现权重基本函数" tabindex="-1"><a class="header-anchor" href="#使用代码实现权重基本函数" aria-hidden="true">#</a> 使用代码实现权重基本函数</h3><div class="language-javascript ext-js"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">Bezier</span><span class="token punctuation">(</span><span class="token parameter"><span class="token number">2</span><span class="token punctuation">,</span>t<span class="token punctuation">,</span>w<span class="token punctuation">[</span><span class="token punctuation">]</span></span><span class="token punctuation">)</span><span class="token operator">:</span>\n  t2 <span class="token operator">=</span> t <span class="token operator">*</span> t\n  mt <span class="token operator">=</span> <span class="token number">1</span><span class="token operator">-</span>t\n  mt2 <span class="token operator">=</span> mt <span class="token operator">*</span> mt\n  <span class="token keyword">return</span> w<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token operator">*</span>mt2 <span class="token operator">+</span> w<span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">]</span><span class="token operator">*</span><span class="token number">2</span><span class="token operator">*</span>mt<span class="token operator">*</span>t <span class="token operator">+</span> w<span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">]</span><span class="token operator">*</span>t2\n\n<span class="token keyword">function</span> <span class="token function">Bezier</span><span class="token punctuation">(</span><span class="token parameter"><span class="token number">3</span><span class="token punctuation">,</span>t<span class="token punctuation">,</span>w<span class="token punctuation">[</span><span class="token punctuation">]</span></span><span class="token punctuation">)</span><span class="token operator">:</span>\n  t2 <span class="token operator">=</span> t <span class="token operator">*</span> t\n  t3 <span class="token operator">=</span> t2 <span class="token operator">*</span> t\n  mt <span class="token operator">=</span> <span class="token number">1</span><span class="token operator">-</span>t\n  mt2 <span class="token operator">=</span> mt <span class="token operator">*</span> mt\n  mt3 <span class="token operator">=</span> mt2 <span class="token operator">*</span> mt\n  <span class="token keyword">return</span> w<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token operator">*</span>mt3 <span class="token operator">+</span> <span class="token number">3</span><span class="token operator">*</span>w<span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">]</span><span class="token operator">*</span>mt2<span class="token operator">*</span>t <span class="token operator">+</span> <span class="token number">3</span><span class="token operator">*</span>w<span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">]</span><span class="token operator">*</span>mt<span class="token operator">*</span>t2 <span class="token operator">+</span> w<span class="token punctuation">[</span><span class="token number">3</span><span class="token punctuation">]</span><span class="token operator">*</span>t3\n</code></pre></div><h2 id="_4-通过svg绘制贝塞尔曲线" tabindex="-1"><a class="header-anchor" href="#_4-通过svg绘制贝塞尔曲线" aria-hidden="true">#</a> 4.通过SVG绘制贝塞尔曲线</h2><p>SVG中绘制平滑曲线的命令有三个，其中两个用来绘制贝塞尔曲线，另外一个用来绘制弧形或者说是圆的一部分。</p><p>虽然贝塞尔曲线的类型有很多，但是在path元素里，只存在两种贝塞尔曲线：三次贝塞尔曲线C，和二次贝塞尔曲线Q，因为在计算机图形领域用的比较多的就是这两个了。</p><h3 id="_1-绘制二次贝塞尔曲线" tabindex="-1"><a class="header-anchor" href="#_1-绘制二次贝塞尔曲线" aria-hidden="true">#</a> [1]绘制二次贝塞尔曲线</h3><p>有两种命令来来二次贝塞尔曲线<code>Q</code>和<code>T</code></p><h4 id="q" tabindex="-1"><a class="header-anchor" href="#q" aria-hidden="true">#</a> Q</h4><div class="language-text ext-text"><pre class="language-text"><code> Q x1 y1, x y (or q dx1 dy1, dx dy) // 控制点 (x1,y1)，终点 (x,y)\n</code></pre></div><p><img src="https://img-blog.csdnimg.cn/img_convert/3bfd18ab8624b9a425f96090cc4ea012.png" alt="image-20220414120812377"></p><h4 id="t" tabindex="-1"><a class="header-anchor" href="#t" aria-hidden="true">#</a> T</h4><div class="language-text ext-text"><pre class="language-text"><code>T x y (or t dx dy) // 终点 (x y)，控制点通过前面的Q命令计算得出\n</code></pre></div><p>快捷命令T会通过前一个控制点，推断出一个新的控制点。这意味着，在你的第一个控制点后面，可以只定义终点，就创建出一个相当复杂的曲线。快捷命令T会通过前一个控制点，推断出一个新的控制点。这意味着，在你的第一个控制点后面，可以只定义终点，就创建出一个相当复杂的曲线。</p><p>示例</p><div class="language-text ext-text"><pre class="language-text"><code>&lt;?xml version=&quot;1.0&quot; standalone=&quot;no&quot;?&gt;\n&lt;svg width=&quot;190px&quot; height=&quot;160px&quot; version=&quot;1.1&quot; xmlns=&quot;http://www.w3.org/2000/svg&quot;&gt;\n  &lt;path d=&quot;M10 80 Q 52.5 10, 95 80 T 180 80&quot; stroke=&quot;black&quot; fill=&quot;transparent&quot;/&gt;\n&lt;/svg&gt;\n</code></pre></div><p><img src="https://img-blog.csdnimg.cn/img_convert/ad7c1c2172652ce3207ae9e6e893fd15.png" alt="image-20220414122040448"></p><h3 id="_2-绘制三次贝塞尔曲线" tabindex="-1"><a class="header-anchor" href="#_2-绘制三次贝塞尔曲线" aria-hidden="true">#</a> [2]绘制三次贝塞尔曲线</h3><p>三次贝塞尔曲线和二次贝塞尔曲线相比就是多一个控制点，原理大致相同4</p><h4 id="c" tabindex="-1"><a class="header-anchor" href="#c" aria-hidden="true">#</a> C</h4><p>也有两种命令来绘制三次贝塞尔曲线<code>C</code>和<code>S</code></p><div class="language-text ext-text"><pre class="language-text"><code>C x1 y1, x2 y2, x y (or c dx1 dy1, dx2 dy2, dx dy)\n</code></pre></div><blockquote><p>参数说明：<code>x y</code>表示的是曲线的终点，另外两个坐标是出终点外的控制点，(x1,y1)是起点的控制点，(x2,y2)是终点的控制点</p></blockquote><p>示例</p><div class="language-text ext-text"><pre class="language-text"><code>&lt;?xml version=&quot;1.0&quot; standalone=&quot;no&quot;?&gt;\n\n&lt;svg width=&quot;190px&quot; height=&quot;160px&quot; version=&quot;1.1&quot; xmlns=&quot;http://www.w3.org/2000/svg&quot;&gt;\n\n  &lt;path d=&quot;M10 10 C 20 20, 40 20, 50 10&quot; stroke=&quot;black&quot; fill=&quot;transparent&quot;/&gt;\n  &lt;path d=&quot;M70 10 C 70 20, 120 20, 120 10&quot; stroke=&quot;black&quot; fill=&quot;transparent&quot;/&gt;\n  &lt;path d=&quot;M130 10 C 120 20, 180 20, 170 10&quot; stroke=&quot;black&quot; fill=&quot;transparent&quot;/&gt;\n  &lt;path d=&quot;M10 60 C 20 80, 40 80, 50 60&quot; stroke=&quot;black&quot; fill=&quot;transparent&quot;/&gt;\n  &lt;path d=&quot;M70 60 C 70 80, 110 80, 110 60&quot; stroke=&quot;black&quot; fill=&quot;transparent&quot;/&gt;\n  &lt;path d=&quot;M130 60 C 120 80, 180 80, 170 60&quot; stroke=&quot;black&quot; fill=&quot;transparent&quot;/&gt;\n  &lt;path d=&quot;M10 110 C 20 140, 40 140, 50 110&quot; stroke=&quot;black&quot; fill=&quot;transparent&quot;/&gt;\n  &lt;path d=&quot;M70 110 C 70 140, 110 140, 110 110&quot; stroke=&quot;black&quot; fill=&quot;transparent&quot;/&gt;\n  &lt;path d=&quot;M130 110 C 120 140, 180 140, 170 110&quot; stroke=&quot;black&quot; fill=&quot;transparent&quot;/&gt;\n\n&lt;/svg&gt;\n</code></pre></div><p><img src="https://img-blog.csdnimg.cn/img_convert/d03e0f8bdf9e19374aaf6f410525ddb7.png" alt="image-20220414122445026"></p><h4 id="s" tabindex="-1"><a class="header-anchor" href="#s" aria-hidden="true">#</a> S</h4><div class="language-text ext-text"><pre class="language-text"><code> S x2 y2, x y (or s dx2 dy2, dx dy)\n</code></pre></div><p>S命令和T命令相似，当你想将若干个贝塞尔曲线连起来，从而创建出一条很长的平滑曲线，这便是一种很好的选择。通常情况下一个点某一侧的控制点是它另一侧的控制点的对称（以保持斜率不变）。这样，你可以使用一个简写的贝塞尔曲线命令S。</p><p>示例：</p><div class="language-text ext-text"><pre class="language-text"><code>&lt;?xml version=&quot;1.0&quot; standalone=&quot;no&quot;?&gt;\n&lt;svg width=&quot;190px&quot; height=&quot;160px&quot; version=&quot;1.1&quot; xmlns=&quot;http://www.w3.org/2000/svg&quot;&gt;\n  &lt;path d=&quot;M10 80 C 40 10, 65 10, 95 80 S 150 150, 180 80&quot; stroke=&quot;black&quot; fill=&quot;transparent&quot;/&gt;\n&lt;/svg&gt;\n</code></pre></div><p>S命令可以用来创建与前面一样的贝塞尔曲线，但是，如果S命令跟在一个C或S命令后面，则它的第一个控制点会被假设成前一个命令曲线的第二个控制点的中心对称点。如果S命令单独使用，前面没有C或S命令，那当前点将作为第一个控制点。</p><p><img src="https://img-blog.csdnimg.cn/img_convert/27a67059b7a9c69eda215d52eb5ea1b5.png" alt="image-20220414123107747"></p><h2 id="_5-通过canvas2d绘制贝塞尔曲线" tabindex="-1"><a class="header-anchor" href="#_5-通过canvas2d绘制贝塞尔曲线" aria-hidden="true">#</a> 5.通过Canvas2D绘制贝塞尔曲线</h2><p>其绘图原理和SVG绘制同</p><div class="language-javascript ext-js"><pre class="language-javascript"><code><span class="token function">quadraticCurveTo</span><span class="token punctuation">(</span>cp1x<span class="token punctuation">,</span> cp1y<span class="token punctuation">,</span> x<span class="token punctuation">,</span> y<span class="token punctuation">)</span>\n</code></pre></div><p>绘制二次贝塞尔曲线，<code>cp1x,cp1y</code>为一个控制点，<code>x,y为</code>结束点。</p><div class="language-text ext-text"><pre class="language-text"><code>bezierCurveTo(cp1x, cp1y, cp2x, cp2y, x, y)\n</code></pre></div><p>绘制三次贝塞尔曲线，<code>cp1x,cp1y</code>为控制点一，<code>cp2x,cp2y</code>为控制点二，<code>x,y</code>为结束点。</p><p><img src="https://img-blog.csdnimg.cn/img_convert/71e22dcaa2a01d96050b438a4e1dd5ea.png" alt="img"></p><p>参考：</p><p>https://zh.javascript.info/bezier-curve</p><p>https://www.youtube.com/watch?v=aVwxzDHniEw</p><p>https://pomax.github.io/bezierinfo/zh-CN/index.html</p><p>https://zh.wikipedia.org/wiki/%E8%B2%9D%E8%8C%B2%E6%9B%B2%E7%B7%9A</p>',92),e={},o=(0,n(3744).Z)(e,[["render",function(a,t){return s}]])},3744:(a,t)=>{t.Z=(a,t)=>{const n=a.__vccOpts||a;for(const[a,s]of t)n[a]=s;return n}}}]);